import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Developer Guides","description":"Our community-written developer guides cover many topics, from creating a mod and setting up your environment, all the way to rendering, networking, data generation and more.","frontmatter":{"title":"Developer Guides","description":"Our community-written developer guides cover many topics, from creating a mod and setting up your environment, all the way to rendering, networking, data generation and more.","authors":["IMB11","its-miroma","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"1.21.10/develop/index.md","filePath":"versions/1.21.10/develop/index.md","lastUpdated":1766682904000}`);var a={name:`1.21.10/develop/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Developer Guides <a class="header-anchor" href="#h1" aria-label="Permalink to “Developer Guides”">​</a></h1><p>Fabric is a lightweight modding toolchain for Minecraft: Java Edition, designed to be simple and easy-to-use. It allows developers to apply modifications (&quot;mods&quot;) to the vanilla game, to add new features or change existing mechanics.</p><p>This documentation will walk you through modding with Fabric, from <a href="./getting-started/creating-a-project">creating your first mod</a> and <a href="./getting-started/setting-up">setting up your environment</a>, to advanced topics like <a href="./rendering/basic-concepts">rendering</a>, <a href="./networking">networking</a>, <a href="./data-generation/setup">data generation</a> and much more.</p><p>Check out the sidebar for a list of the available pages.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>In case you need it at any time, a fully-working mod with all the source code of this documentation is available in the <a href="https://github.com/FabricMC/fabric-docs/tree/main/reference/1.21.10" target="_blank" rel="noreferrer"><code>/reference</code> folder on GitHub</a>.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><p>Before you start modding with Fabric, you need to have some understanding of developing with Java, and of Object-Oriented Programming in general.</p><p>Here are some resources that might help you familiarize with Java and OOP:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h2 id="what-does-fabric-offer" tabindex="-1">What Does Fabric Offer? <a class="header-anchor" href="#what-does-fabric-offer" aria-label="Permalink to “What Does Fabric Offer?”">​</a></h2><p>The Fabric Project is centered around three main components:</p><ul><li><strong>Fabric Loader</strong>: a flexible, platform-independent loader of mods, primarily designed for Minecraft: Java Edition</li><li><strong>Fabric API</strong>: a complementary set of APIs and tools mod developers can use when creating mods</li><li><strong>Fabric Loom</strong>: a <a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a> plugin, enabling developers to easily develop and debug mods</li></ul><h3 id="what-does-fabric-api-offer" tabindex="-1">What Does Fabric API Offer? <a class="header-anchor" href="#what-does-fabric-api-offer" aria-label="Permalink to “What Does Fabric API Offer?”">​</a></h3><p>Fabric API provides a wide set of APIs that build on top of the vanilla functionality to allow advanced or simpler development.</p><p>For example, it provides new hooks, events, utilities such as transitive access wideners, access to internal registries such as the compostable items registry, and more.</p>`,15)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};